  if (n == 6) { a=1; b=0; c=1; d=1; e=1; f=1; g=1; }
  if (n == 7) { a=1; b=1; c=1; d=0; e=0; f=0; g=0; }
  if (n == 8) { a=1; b=1; c=1; d=1; e=1; f=1; g=1; }
  if (n == 9) { a=1; b=1; c=1; d=1; e=0; f=1; g=1; }
  digitalWrite(SEG_A, a);
  digitalWrite(SEG_B, b);
  digitalWrite(SEG_C, c);
  digitalWrite(SEG_D, d);
  digitalWrite(SEG_E, e);
  digitalWrite(SEG_F, f);
