  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(BTN_PIN, INPUT);
  showDigit(0);
}

void loop() {
  int btnState = digitalRead(BTN_PIN);
  if (btnState == HIGH && lastBtnState == LOW) {
    counter = counter + 1;
    if (counter > 9) { counter = 0; }
    showDigit(counter);
    delay(50);
  }
  lastBtnState = btnState;
}

